"use client"

import { motion, useReducedMotion } from "framer-motion"
import { Logo } from "@/components/logo"
import { Badge } from "@/components/ui/badge"
import Image from "next/image"

// ─── Easing ───────────────────────────────────────────────────────────────────
// Strong expo ease-out — starts fast, feels immediately responsive.
const expo = [0.16, 1, 0.3, 1] as const

// ─── Variants ─────────────────────────────────────────────────────────────────

// Badge row lines: scaleX reveal from origin point.
const lineVariant = {
    hidden: { scaleX: 0, opacity: 0 },
    visible: {
        scaleX: 1,
        opacity: 1,
        transition: { duration: 0.7, ease: expo, delay: 0.1 },
    },
}

// Badge pill: translateY + opacity only.
const badgeVariant = {
    hidden: { opacity: 0, y: 8 },
    visible: {
        opacity: 1,
        y: 0,
        transition: { duration: 0.6, ease: expo },
    },
}

// Heading: translateY + opacity.
const headingVariant = {
    hidden: { opacity: 0, y: 20 },
    visible: {
        opacity: 1,
        y: 0,
        transition: { duration: 0.8, ease: expo, delay: 0.15 },
    },
}

// Description: cascades just after heading.
const descVariant = {
    hidden: { opacity: 0, y: 16 },
    visible: {
        opacity: 1,
        y: 0,
        transition: { duration: 0.75, ease: expo, delay: 0.25 },
    },
}

// Step cards group: stagger cascade.
const stepsGroupVariant = {
    hidden: {},
    visible: {
        transition: { staggerChildren: 0.07, delayChildren: 0.1 },
    },
}

// Card entrance: scale(0.95) + opacity.
const stepCardVariant = {
    hidden: { opacity: 0, scale: 0.95 },
    visible: {
        opacity: 1,
        scale: 1,
        transition: { duration: 0.5, ease: expo },
    },
}

// Right panel: slides up slightly after cards begin.
const panelVariant = {
    hidden: { opacity: 0, y: 24 },
    visible: {
        opacity: 1,
        y: 0,
        transition: { duration: 0.8, ease: expo, delay: 0.15 },
    },
}

// Reduced-motion: opacity only, no movement.
const fadeOnly = {
    hidden: { opacity: 0 },
    visible: { opacity: 1, transition: { duration: 0.4 } },
}

const fadeOnlyGroup = {
    hidden: {},
    visible: { transition: { staggerChildren: 0.05 } },
}

// ─── Step data ────────────────────────────────────────────────────────────────

const steps = [
    {
        title: "Choose your role",
        description: "Select whether you're joining as an employee or team manager",
    },
    {
        title: "Set up your profile",
        description: "Add your details and preferences so your team knows who you are",
    },
    {
        title: "Sync your workspace",
        description: "Connect your tools and get straight into working with your team",
    },
]

// ─── HowItWorksSection ────────────────────────────────────────────────────────

export default function HowItWorksSection() {
    const shouldReduceMotion = useReducedMotion()

    const line = shouldReduceMotion ? fadeOnly : lineVariant
    const badge = shouldReduceMotion ? fadeOnly : badgeVariant
    const heading = shouldReduceMotion ? fadeOnly : headingVariant
    const desc = shouldReduceMotion ? fadeOnly : descVariant
    const stepsGrp = shouldReduceMotion ? fadeOnlyGroup : stepsGroupVariant
    const stepCard = shouldReduceMotion ? fadeOnly : stepCardVariant
    const rightPanel = shouldReduceMotion ? fadeOnly : panelVariant

    return (
        <section className="w-full bg-background py-16 sm:py-20 md:py-24 overflow-hidden">
            <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 flex flex-col items-center gap-12 sm:gap-14 md:gap-16">

                {/* ── Header ─────────────────────────────────────────────────────── */}
                <div className="flex flex-col items-center gap-6 sm:gap-8 w-full text-center">

                    {/* Badge row */}
                    <div className="flex items-center justify-center gap-2 sm:gap-3">
                        <motion.div
                            className="flex items-center origin-right"
                            variants={line}
                            initial="hidden"
                            whileInView="visible"
                            viewport={{ once: true, margin: "-40px" }}
                        >
                            <div className="w-12 sm:w-20 lg:w-32 h-px bg-gradient-to-l from-primary/30 to-transparent" />
                        </motion.div>

                        <motion.div
                            variants={badge}
                            initial="hidden"
                            whileInView="visible"
                            viewport={{ once: true, margin: "-40px" }}
                        >
                            <Badge variant="hero">
                                <span className="text-sm font-normal">How it works</span>
                            </Badge>
                        </motion.div>

                        <motion.div
                            className="flex items-center origin-left"
                            variants={line}
                            initial="hidden"
                            whileInView="visible"
                            viewport={{ once: true, margin: "-40px" }}
                        >
                            <div className="w-12 sm:w-20 lg:w-32 h-px bg-gradient-to-r from-primary/30 to-transparent" />
                        </motion.div>
                    </div>

                    {/* Heading */}
                    <motion.h2
                        className="text-3xl sm:text-4xl md:text-5xl lg:text-6xl font-normal leading-tight text-foreground px-4 text-balance"
                        variants={heading}
                        initial="hidden"
                        whileInView="visible"
                        viewport={{ once: true, margin: "-40px" }}
                    >
                        Start fast, join your team easier
                    </motion.h2>

                    {/* Description */}
                    <motion.p
                        className="max-w-xl text-sm sm:text-base font-normal leading-relaxed text-muted-foreground px-4"
                        variants={desc}
                        initial="hidden"
                        whileInView="visible"
                        viewport={{ once: true, margin: "-40px" }}
                    >
                        Set up your profile in minutes and sync with your workspace.
                        <br className="hidden sm:block" />
                        No friction, no confusion — just flow.
                    </motion.p>
                </div>

                {/* ── Two-column layout ──────────────────────────────────────────── */}
                <div className="w-full grid grid-cols-1 lg:grid-cols-2 gap-4 items-start">

                    {/* Left — step cards inside a themed container */}
                    <motion.div
                        className="w-full p-2 bg-secondary/50 rounded-[28px] border border-border/50 flex flex-col gap-2"
                        variants={stepsGrp}
                        initial="hidden"
                        whileInView="visible"
                        viewport={{ once: true, margin: "-60px" }}
                    >
                        {steps.map((step) => (
                            <motion.div
                                key={step.title}
                                variants={stepCard}
                                style={{ willChange: "transform, opacity" }}
                                className="w-full bg-background rounded-[22px] px-8 py-8 border border-border/40 flex flex-col gap-4 shadow-sm"
                            >
                                <div className="flex size-14 items-center justify-center rounded-2xl bg-secondary/80 border border-border/60">
                                    <Logo className="size-8 text-primary" />
                                </div>
                                <div className="space-y-1.5">
                                    <h3 className="text-lg font-medium text-foreground leading-snug">
                                        {step.title}
                                    </h3>
                                    <p className="text-sm font-normal text-muted-foreground leading-relaxed max-w-[320px]">
                                        {step.description}
                                    </p>
                                </div>
                            </motion.div>
                        ))}
                    </motion.div>

                    {/* Right — Phone Mockup Panel */}
                    <motion.div
                        variants={rightPanel}
                        initial="hidden"
                        whileInView="visible"
                        viewport={{ once: true, margin: "-60px" }}
                        style={{ willChange: "transform, opacity" }}
                        className="relative w-full aspect-[4/5] lg:aspect-auto lg:h-full min-h-[400px] bg-secondary/30 border border-border/50 rounded-[28px] lg:self-stretch overflow-hidden group"
                    >
                        <Image
                            src="/assets/phone.png"
                            alt="Mockup Preview"
                            fill
                            className="object-cover transition-transform duration-700 ease-expo group-hover:scale-105"
                            priority
                        />
                        {/* Subtle overlay for depth */}
                        <div className="absolute inset-0 bg-gradient-to-t from-background/20 to-transparent pointer-events-none" />
                    </motion.div>

                </div>

            </div>
        </section>
    )
}

import type * as React from "react"
import { Slot } from "@radix-ui/react-slot"
import { cva, type VariantProps } from "class-variance-authority"

import { cn } from "@/lib/utils"

const badgeVariants = cva(
  "inline-flex items-center justify-center rounded-md border px-2 py-0.5 text-xs font-medium w-fit whitespace-nowrap shrink-0 [&>svg]:size-3 gap-1 [&>svg]:pointer-events-none focus-visible:border-ring focus-visible:ring-ring/50 focus-visible:ring-[3px] aria-invalid:ring-destructive/20 dark:aria-invalid:ring-destructive/40 aria-invalid:border-destructive transition-[color,box-shadow] overflow-hidden",
  {
    variants: {
      variant: {
        default: "border-transparent bg-primary text-primary-foreground [a&]:hover:bg-primary/90",
        secondary: "border-transparent bg-secondary text-secondary-foreground [a&]:hover:bg-secondary/90",
        destructive:
          "border-transparent bg-destructive text-white [a&]:hover:bg-destructive/90 focus-visible:ring-destructive/20 dark:focus-visible:ring-destructive/40 dark:bg-destructive/60",
        outline: "text-foreground [a&]:hover:bg-accent [a&]:hover:text-accent-foreground",
        hero: "border-border/50 bg-secondary/50 text-foreground backdrop-blur-sm px-4 py-2 rounded-full",
      },
    },
    defaultVariants: {
      variant: "default",
    },
  },
)

function Badge({
  className,
  variant,
  asChild = false,
  ...props
}: React.ComponentProps<"span"> & VariantProps<typeof badgeVariants> & { asChild?: boolean }) {
  const Comp = asChild ? Slot : "span"

  return <Comp data-slot="badge" className={cn(badgeVariants({ variant }), className)} {...props} />
}

export { Badge, badgeVariants }

"use client"

import { useState } from "react"
import { Button } from "@/components/ui/button"
import { Badge } from "@/components/ui/badge"
import { Box, Layers, Zap } from "lucide-react"

const plans = [
  {
    name: "Basic plan",
    price: 9,
    description:
      "Perfect for small businesses or startups, our Starter Plan gives you the essential tools to manage your finances with ease",
    icon: Box,
  },
  {
    name: "Pro plan",
    price: 19,
    description:
      "Designed for growing businesses, the Basic Plan expands on our Starter package with additional features",
    icon: Layers,
  },
  {
    name: "Enterprise plan",
    price: 49,
    description:
      "Tailored for large enterprises, this plan offers advanced features, personalized support, and the scalability.",
    icon: Zap,
  },
]

const PricingSection2 = () => {
  const [isYearly, setIsYearly] = useState(false)

  return (
    <section className="relative py-16 sm:py-20 md:py-28 overflow-hidden">
      {/* Header */}
      <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 mb-12 sm:mb-16">
        <div className="flex flex-col items-center text-center gap-6 sm:gap-8">
          {/* Badge */}
          <div className="flex items-center justify-center gap-2 sm:gap-3">
            <div className="flex items-center">
              <div className="w-12 sm:w-20 h-px bg-gradient-to-l from-primary/30 to-transparent"></div>
            </div>

            <Badge variant="hero" className="group">
              <span className="text-sm font-normal">Pricing</span>
            </Badge>

            <div className="flex items-center">
              <div className="w-12 sm:w-20 h-px bg-gradient-to-r from-primary/30 to-transparent"></div>
            </div>
          </div>

          {/* Heading and Description */}
          <div className="flex flex-col items-center gap-4 sm:gap-6">
            <h2 className="text-3xl sm:text-4xl md:text-5xl lg:text-6xl font-normal leading-tight text-foreground px-4">
              Simple and transparent pricing
            </h2>

            <p className="max-w-3xl text-muted-foreground text-sm sm:text-base font-normal leading-relaxed px-4">
              Choose a plan that fits your business needs and budget. No hidden fees, no surprises—just straightforward
              pricing for powerful financial management.
            </p>
          </div>
        </div>
      </div>

      {/* Toggle */}
      <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 mb-12 sm:mb-16 flex justify-center">
        <div className="relative bg-muted/30 backdrop-blur-sm rounded-full p-2 border border-border inline-flex shadow-sm">
          <div
            className="absolute top-2 bottom-2 bg-card rounded-full shadow-md transition-all duration-300 ease-out"
            style={{
              left: isYearly ? "50%" : "0.5rem",
              right: isYearly ? "0.5rem" : "50%",
            }}
          />

          <button
            onClick={() => setIsYearly(false)}
            className={`relative z-10 px-6 sm:px-8 py-3 rounded-full font-medium text-sm sm:text-base transition-colors ${
              !isYearly ? "text-foreground" : "text-muted-foreground"
            }`}
          >
            Monthly
          </button>

          <button
            onClick={() => setIsYearly(true)}
            className={`relative z-10 px-6 sm:px-8 py-3 rounded-full font-medium text-sm sm:text-base transition-colors ${
              isYearly ? "text-foreground" : "text-muted-foreground"
            }`}
          >
            Yearly
          </button>
        </div>
      </div>

      {/* Pricing Cards */}
      <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8">
        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6 lg:gap-8">
          {plans.map((plan, index) => {
            const Icon = plan.icon
            return (
              <div
                key={index}
                className="relative flex flex-col bg-card rounded-3xl p-6 sm:p-8 border border-border transition-all duration-300 group hover:-translate-y-2 hover:border-primary/30 hover:shadow-[var(--shadow-card)]"
              >
                {/* Hover glow effect */}
                <div className="absolute inset-0 rounded-3xl bg-gradient-to-br from-primary/5 via-transparent to-transparent opacity-0 group-hover:opacity-100 transition-opacity duration-300" />

                {/* Header with icon and name */}
                <div className="relative z-10 flex items-center gap-4 mb-8">
                  {/* Icon */}
                  <div className="w-16 h-16 rounded-full flex items-center justify-center border border-border bg-secondary/50 backdrop-blur-sm transition-all duration-300 group-hover:scale-110 group-hover:border-primary/50 group-hover:bg-primary/10">
                    <Icon className="w-6 h-6 text-primary" />
                  </div>

                  {/* Plan Name */}
                  <h3 className="text-xl font-normal text-foreground">{plan.name}</h3>
                </div>

                {/* Price */}
                <div className="relative z-10 flex items-end gap-2 mb-6">
                  <span className="text-4xl sm:text-5xl font-normal text-foreground">
                    ${isYearly ? plan.price * 10 : plan.price}
                  </span>
                  <span className="text-base text-muted-foreground mb-2">/Month</span>
                </div>

                {/* Description */}
                <p className="relative z-10 text-sm sm:text-base text-muted-foreground leading-relaxed mb-8 flex-1">
                  {plan.description}
                </p>

                {/* CTA Button */}
                <div className="relative z-10">
                  <Button className="w-full rounded-full py-6 font-medium bg-card border-2 border-primary text-primary hover:bg-primary hover:text-primary-foreground transition-all duration-300">
                    Get started
                  </Button>
                </div>
              </div>
            )
          })}
        </div>
      </div>
    </section>
  )
}

export default PricingSection2

